#include<bits/stdc++.h>
using namespace std;

const int MAX=32768; 
int t,n;
int dp[33000][5]={1};

int main()
{
	for (int i=1;i*i<=MAX;i++)
		for (int j=i*i;j<=MAX;j++)
			for (int sum=1;sum<=4;sum++)
				dp[j][sum]+=dp[j-i*i][sum-1];
	cin>>t;
	while(t--)
	{
		int n,ans=0;
		cin>>n;
		for (int i=1;i<=4;i++)
			ans+=dp[n][i];
		cout<<ans<<"\n";
	}
	return 0;
}
